mapper.select:
select comment.*, user.name as userName, user.avatar as userAvatar
from comment
left join user on comment.user_id = user.id

     and comment.content like concat('%', #{content}, '%')
     and comment.user_id = #{userId}
     and comment.fid = #{fid}
     and comment.module = #{module}
     and comment.root_id = #{rootId}

order by comment.id desc

select comment.*, user.name as userName, user.avatar as userAvatar
from comment
left join user on comment.user_id = user.id

     and comment.content like concat('%', #{query.content}, '%')
     and comment.user_id = #{query.userId}
     and comment.fid = #{query.fid}
     and comment.module = #{query.module}
     and comment.root_id = #{query.rootId}

order by comment.id desc

select comment.*, user.name as userName, user.avatar as userAvatar, u2.name as parentUserName from comment left join user on comment.user_id = user.id left join comment c2 on comment.pid = c2.id left join user u2 on c2.user_id = u2.id where comment.root_id in
#{rootId}
and comment.pid is not null order by comment.id desc
